contracts/core/Config.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "@openzeppelin/contracts/access/AccessControl.sol";
import "@openzeppelin/contracts/utils/Pausable.sol";

/**
 * @title Config
 * @notice 参数配置管理合约 - 所有可调参数唯一存储
 * @dev 所有修改必须通过 Timelock，并 emit 新旧值
 */
contract Config is AccessControl, Pausable {
    // ==================== 角色定义 ====================
    bytes32 public constant DAO_ROLE = keccak256("DAO_ROLE");
    bytes32 public constant OPERATOR_ROLE = keccak256("OPERATOR_ROLE");
    bytes32 public constant GUARDIAN_ROLE = keccak256("GUARDIAN_ROLE");

    // ==================== 时间常量 ====================
    uint256 public rfqValidityPeriod = 2 hours;              // RFQ有效期
    uint256 public quoteValidityPeriod = 30 minutes;         // 报价有效期
    uint256 public initialFeedDeadline = 10 minutes;         // 初始喂价时限
    uint256 public closingFeedDeadline = 10 minutes;         // 平仓喂价时限
    uint256 public defaultMarginCallDeadline = 12 hours;     // 默认追保截止时间
    uint256 public cryptoMarginCallDeadline = 2 hours;       // 加密货币追保截止时间
    uint256 public settlementArbitrationWindow = 24 hours;   // 平仓结算仲裁窗口
    uint256 public defaultArbitrationWindow = 12 hours;      // 其他场景仲裁窗口

    // ==================== 费率常量 (基点 1 = 0.01%) ====================
    uint256 public creationFee = 1 ether;                    // 建仓手续费：1U
    uint256 public tradingFeeRate = 10;                      // 交易手续费：0.1%
    uint256 public arbitrationFee = 30 ether;                // 仲裁费：30U
    uint256 public nstDiscount = 80;                         // NST折扣：80%

    // ==================== 喂价费用 ====================
    uint256 public feedFee_5_3 = 3 ether;                    // 5-3档：3U
    uint256 public feedFee_7_5 = 5 ether;                    // 7-5档：5U
    uint256 public feedFee_10_7 = 8 ether;                   // 10-7档：8U
    uint256 public feedPlatformShare = 10;                   // 平台抽成：10%
    uint256 public feedFeederShare = 90;                     // 喂价员分配：90%

    // ==================== 保证金参数 ====================
    uint256 public minMarginRate = 1000;                     // 最低保证金率：10%（自由卖方）
    uint256 public seatSellerInitialMargin = 0;              // 席位卖方初始保证金：0

    // ==================== 喂价员参数 ====================
    uint256 public minFeederStake = 100 ether;               // 喂价员最低质押：100U

    // ==================== 限制参数 ====================
    uint256 public maxQuotesPerBuyerOrder = 5;               // 买方单最大报价数
    uint256 public maxQuotesPerSellerOrder = 1;              // 卖方单报价即成交
    uint256 public maxConsecutiveDays = 10;                  // 最大连续天数
    uint256 public defaultDailyLimitPercent = 30;            // 默认单日涨幅阈值
    uint256 public minExerciseDelay = 1;                     // 最小行权延迟T+1
    uint256 public maxExerciseDelay = 5;                     // 最大行权延迟T+5

    // ==================== 积分参数 ====================
    uint256 public pointsMultiplier = 100;                   // 积分倍率：1U = 100分

    // ==================== 资金池分配比例 (基点 100 = 1%) ====================
    uint256 public nodeRewardShare = 500;                    // 节点奖励：5%
    uint256 public tokenBuybackShare = 1000;                 // 代币回购：10%
    uint256 public lpPoolShare = 1000;                       // LP池：10%
    uint256 public teamFundShare = 3000;                     // 团队：30%
    uint256 public foundationShare = 2500;                   // 基金会：25%
    uint256 public daoShare = 1000;                          // DAO：10%
    uint256 public growthNodeShare = 1000;                   // 成长节点：10%

    // ==================== 合约地址 ====================
    address public usdtAddress;
    address public usdcAddress;
    address public nstTokenAddress;
    address public vaultManagerAddress;
    address public optionsCoreAddress;
    address public feedProtocolAddress;
    address public seatManagerAddress;
    address public pointsManagerAddress;

    // ==================== 事件 ====================
    event ParameterUpdated(
        string indexed paramName,
        uint256 oldValue,
        uint256 newValue,
        uint256 timestamp
    );

    event AddressUpdated(
        string indexed paramName,
        address oldAddress,
        address newAddress,
        uint256 timestamp
    );

    // ==================== 构造函数 ====================
    constructor(address _admin) {
        _grantRole(DEFAULT_ADMIN_ROLE, _admin);
        _grantRole(DAO_ROLE, _admin);
        _grantRole(OPERATOR_ROLE, _admin);
        _grantRole(GUARDIAN_ROLE, _admin);
    }

    // ==================== 修改器 ====================
    modifier onlyDAO() {
        require(hasRole(DAO_ROLE, msg.sender), "Config: caller is not DAO");
        _;
    }

    modifier onlyOperator() {
        require(hasRole(OPERATOR_ROLE, msg.sender), "Config: caller is not Operator");
        _;
    }

    modifier onlyGuardian() {
        require(hasRole(GUARDIAN_ROLE, msg.sender), "Config: caller is not Guardian");
        _;
    }

    // ==================== 暂停功能 ====================
    function pause() external onlyGuardian {
        _pause();
    }

    function unpause() external onlyDAO {
        _unpause();
    }

    // ==================== 参数设置函数 ====================
    
    /**
     * @notice 设置 RFQ 有效期
     */
    function setRfqValidityPeriod(uint256 _value) external onlyDAO {
        uint256 oldValue = rfqValidityPeriod;
        rfqValidityPeriod = _value;
        emit ParameterUpdated("rfqValidityPeriod", oldValue, _value, block.timestamp);
    }

    /**
     * @notice 设置报价有效期
     */
    function setQuoteValidityPeriod(uint256 _value) external onlyDAO {
        uint256 oldValue = quoteValidityPeriod;
        quoteValidityPeriod = _value;
        emit ParameterUpdated("quoteValidityPeriod", oldValue, _value, block.timestamp);
    }

    /**
     * @notice 设置建仓手续费
     */
    function setCreationFee(uint256 _value) external onlyDAO {
        uint256 oldValue = creationFee;
        creationFee = _value;
        emit ParameterUpdated("creationFee", oldValue, _value, block.timestamp);
    }

    /**
     * @notice 设置交易手续费率
     */
    function setTradingFeeRate(uint256 _value) external onlyDAO {
        uint256 oldValue = tradingFeeRate;
        tradingFeeRate = _value;
        emit ParameterUpdated("tradingFeeRate", oldValue, _value, block.timestamp);
    }

    /**
     * @notice 设置仲裁费
     */
    function setArbitrationFee(uint256 _value) external onlyDAO {
        uint256 oldValue = arbitrationFee;
        arbitrationFee = _value;
        emit ParameterUpdated("arbitrationFee", oldValue, _value, block.timestamp);
    }

    /**
     * @notice 设置最低保证金率
     */
    function setMinMarginRate(uint256 _value) external onlyDAO {
        uint256 oldValue = minMarginRate;
        minMarginRate = _value;
        emit ParameterUpdated("minMarginRate", oldValue, _value, block.timestamp);
    }

    /**
     * @notice 设置喂价员最低质押
     */
    function setMinFeederStake(uint256 _value) external onlyDAO {
        uint256 oldValue = minFeederStake;
        minFeederStake = _value;
        emit ParameterUpdated("minFeederStake", oldValue, _value, block.timestamp);
    }

    // ==================== 地址设置函数 ====================

    /**
     * @notice 设置 USDT 地址
     */
    function setUsdtAddress(address _address) external onlyDAO {
        address oldAddress = usdtAddress;
        usdtAddress = _address;
        emit AddressUpdated("usdtAddress", oldAddress, _address, block.timestamp);
    }

    /**
     * @notice 设置 VaultManager 地址
     */
    function setVaultManagerAddress(address _address) external onlyDAO {
        address oldAddress = vaultManagerAddress;
        vaultManagerAddress = _address;
        emit AddressUpdated("vaultManagerAddress", oldAddress, _address, block.timestamp);
    }

    /**
     * @notice 设置 OptionsCore 地址
     */
    function setOptionsCoreAddress(address _address) external onlyDAO {
        address oldAddress = optionsCoreAddress;
        optionsCoreAddress = _address;
        emit AddressUpdated("optionsCoreAddress", oldAddress, _address, block.timestamp);
    }

    /**
     * @notice 设置 FeedProtocol 地址
     */
    function setFeedProtocolAddress(address _address) external onlyDAO {
        address oldAddress = feedProtocolAddress;
        feedProtocolAddress = _address;
        emit AddressUpdated("feedProtocolAddress", oldAddress, _address, block.timestamp);
    }

    /**
     * @notice 设置 SeatManager 地址
     */
    function setSeatManagerAddress(address _address) external onlyDAO {
        address oldAddress = seatManagerAddress;
        seatManagerAddress = _address;
        emit AddressUpdated("seatManagerAddress", oldAddress, _address, block.timestamp);
    }

    /**
     * @notice 设置 PointsManager 地址
     */
    function setPointsManagerAddress(address _address) external onlyDAO {
        address oldAddress = pointsManagerAddress;
        pointsManagerAddress = _address;
        emit AddressUpdated("pointsManagerAddress", oldAddress, _address, block.timestamp);
    }

    // ==================== 查询函数 ====================

    /**
     * @notice 获取喂价费用
     * @param tier 喂价档位 (0=5-3, 1=7-5, 2=10-7)
     */
    function getFeedFee(uint8 tier) external view returns (uint256) {
        if (tier == 0) return feedFee_5_3;
        if (tier == 1) return feedFee_7_5;
        if (tier == 2) return feedFee_10_7;
        revert("Config: invalid feed tier");
    }

    /**
     * @notice 获取追保截止时间
     * @param isCrypto 是否为加密货币/外汇
     */
    function getMarginCallDeadline(bool isCrypto) external view returns (uint256) {
        return isCrypto ? cryptoMarginCallDeadline : defaultMarginCallDeadline;
    }

    /**
     * @notice 获取仲裁窗口
     * @param isSettlement 是否为平仓结算
     */
    function getArbitrationWindow(bool isSettlement) external view returns (uint256) {
        return isSettlement ? settlementArbitrationWindow : defaultArbitrationWindow;
    }
}

contracts/core/OptionsCore.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "@openzeppelin/contracts/token/ERC20/IERC20.sol";
import "@openzeppelin/contracts/token/ERC20/utils/SafeERC20.sol";
import "@openzeppelin/contracts/access/AccessControl.sol";
import "@openzeppelin/contracts/utils/ReentrancyGuard.sol";
import "@openzeppelin/contracts/utils/Pausable.sol";
import "../libraries/NSTTypes.sol";
import "../interfaces/IOptionsCore.sol";
import "../vault/VaultManager.sol";
import "./Config.sol";

/**
 * @title OptionsCore
 * @notice 期权核心合约 - 订单创建、匹配、结算
 * @dev 继承 IOptionsCore 接口，实现所有核心功能
 */
contract OptionsCore is IOptionsCore, AccessControl, ReentrancyGuard, Pausable {
    using SafeERC20 for IERC20;

    // ==================== 状态变量 ====================
    Config public config;
    VaultManager public vaultManager;
    IERC20 public usdt;

    uint256 public nextOrderId = 1;
    uint256 public nextQuoteId = 1;

    // 订单存储
    mapping(uint256 => Order) public orders;
    mapping(uint256 => Quote[]) public orderQuotes;
    mapping(uint256 => Quote) public quotes;

    // 用户订单索引
    mapping(address => uint256[]) public buyerOrders;
    mapping(address => uint256[]) public sellerOrders;

    // 订单检索索引
    mapping(string => uint256[]) private ordersByCountry;
    mapping(string => uint256[]) private ordersByMarket;
    mapping(string => uint256[]) private ordersByCode;

    // ==================== 构造函数 ====================
    constructor(
        address _config,
        address _vaultManager,
        address _usdt,
        address _admin
    ) {
        config = Config(_config);
        vaultManager = VaultManager(_vaultManager);
        usdt = IERC20(_usdt);
        
        _grantRole(DEFAULT_ADMIN_ROLE, _admin);
    }

    // ==================== 修改器 ====================
    modifier validOrder(uint256 orderId) {
        require(orderId > 0 && orderId < nextOrderId, "OptionsCore: invalid order id");
        _;
    }

    modifier onlyBuyer(uint256 orderId) {
        require(msg.sender == orders[orderId].buyer, "OptionsCore: not buyer");
        _;
    }

    modifier onlySeller(uint256 orderId) {
        require(msg.sender == orders[orderId].seller, "OptionsCore: not seller");
        _;
    }

    modifier inStatus(uint256 orderId, OrderStatus expectedStatus) {
        require(orders[orderId].status == expectedStatus, "OptionsCore: invalid order status");
        _;
    }

    // ==================== 买方功能实现 ====================

    /**
     * @notice 买方创建询价订单
     */
    function createBuyerRFQ(
        string calldata underlyingName,
        string calldata underlyingCode,
        string calldata market,
        string calldata country,
        string calldata refPrice,
        Direction direction,
        uint256 notionalUSDT,
        uint256 expiryTimestamp,
        uint256 maxPremiumRate,
        uint256 minMarginRate,
        SellerType acceptedSellerType,
        address designatedSeller,
        uint256 arbitrationWindow,
        uint256 marginCallDeadline,
        bool dividendAdjustment
    ) external override nonReentrant whenNotPaused returns (uint256 orderId) {
        require(notionalUSDT > 0, "OptionsCore: notional must be positive");
        require(expiryTimestamp > block.timestamp, "OptionsCore: expiry must be in future");
        require(minMarginRate >= config.minMarginRate(), "OptionsCore: margin rate too low");

        // 收取建仓手续费 1U
        usdt.safeTransferFrom(msg.sender, address(vaultManager), config.creationFee());
        
        orderId = nextOrderId++;

        Order storage order = orders[orderId];
        order.orderId = orderId;
        order.buyer = msg.sender;
        order.underlyingName = underlyingName;
        order.underlyingCode = underlyingCode;
        order.market = market;
        order.country = country;
        order.refPrice = refPrice;
        order.direction = direction;
        order.notionalUSDT = notionalUSDT;
        order.expiryTimestamp = expiryTimestamp;
        order.premiumRate = maxPremiumRate;
        order.minMarginRate = minMarginRate;
        order.sellerType = acceptedSellerType;
        order.designatedSeller = designatedSeller;
        order.arbitrationWindow = arbitrationWindow;
        order.marginCallDeadline = marginCallDeadline;
        order.dividendAdjustment = dividendAdjustment;
        order.status = OrderStatus.RFQ_CREATED;
        order.createdAt = block.timestamp;

        // 添加到用户订单列表
        buyerOrders[msg.sender].push(orderId);

        // 添加到检索索引
        ordersByCountry[country].push(orderId);
        ordersByMarket[market].push(orderId);
        ordersByCode[underlyingCode].push(orderId);

        emit OrderCreated(orderId, msg.sender, true, block.timestamp);
        emit OrderStatusChanged(orderId, OrderStatus.RFQ_CREATED, OrderStatus.RFQ_CREATED, "created", block.timestamp);

        return orderId;
    }

    /**
     * @notice 买方选择卖方报价成交
     */
    function acceptQuote(uint256 quoteId) external override nonReentrant whenNotPaused {
        Quote storage quote = quotes[quoteId];
        require(quote.status == QuoteStatus.Active, "OptionsCore: quote not active");
        require(block.timestamp <= quote.expiresAt, "OptionsCore: quote expired");

        Order storage order = orders[quote.orderId];
        require(msg.sender == order.buyer, "OptionsCore: not buyer");
        require(order.status == OrderStatus.RFQ_CREATED || order.status == OrderStatus.QUOTING, "OptionsCore: invalid status");
        require(quote.premiumRate <= order.premiumRate, "OptionsCore: premium rate exceeds max");

        // 更新报价状态
        quote.status = QuoteStatus.Accepted;

        // 更新订单信息
        order.seller = quote.seller;
        order.sellerType = quote.sellerType;
        order.premiumRate = quote.premiumRate;
        order.premiumAmount = quote.premiumAmount;
        order.initialMargin = quote.marginAmount;
        order.currentMargin = quote.marginAmount;
        order.liquidationRule = quote.liquidationRule;
        order.consecutiveDays = quote.consecutiveDays;
        order.dailyLimitPercent = quote.dailyLimitPercent;
        
        OrderStatus oldStatus = order.status;
        order.status = OrderStatus.MATCHED;
        order.matchedAt = block.timestamp;

        // 买方支付期权费 + 交易手续费
        uint256 tradingFee = (order.notionalUSDT * config.tradingFeeRate()) / 10000;
        uint256 totalPayment = quote.premiumAmount + tradingFee;
        usdt.safeTransferFrom(msg.sender, address(vaultManager), totalPayment);

        // 添加到卖方订单列表
        sellerOrders[quote.seller].push(order.orderId);

        // 将其他报价设为拒绝
        Quote[] storage allQuotes = orderQuotes[order.orderId];
        for (uint256 i = 0; i < allQuotes.length; i++) {
            if (allQuotes[i].quoteId != quoteId && allQuotes[i].status == QuoteStatus.Active) {
                allQuotes[i].status = QuoteStatus.Rejected;
            }
        }

        emit OrderMatched(order.orderId, order.buyer, order.seller, block.timestamp);
        emit OrderStatusChanged(order.orderId, oldStatus, OrderStatus.MATCHED, "quote accepted", block.timestamp);
    }

    /**
     * @notice 买方发起喂价请求
     */
    function requestFeed(uint256 orderId, FeedTier tier) external payable override 
        validOrder(orderId) 
        onlyBuyer(orderId) 
        nonReentrant 
        whenNotPaused 
    {
        // 喂价逻辑将在 FeedProtocol 合约中实现
        // 这里只是接口预留
        revert("OptionsCore: feed protocol not implemented yet");
    }

    /**
     * @notice 买方提前行权
     */
    function earlyExercise(uint256 orderId) external override 
        validOrder(orderId) 
        onlyBuyer(orderId) 
        inStatus(orderId, OrderStatus.LIVE) 
        nonReentrant 
        whenNotPaused 
    {
        Order storage order = orders[orderId];
        
        // 检查 T+X 条件
        uint256 requiredDelay = uint256(order.exerciseDelay) * 1 days;
        require(
            block.timestamp >= order.matchedAt + requiredDelay,
            "OptionsCore: exercise delay not met"
        );

        OrderStatus oldStatus = order.status;
        order.status = OrderStatus.WAITING_FINAL_FEED;

        emit OrderStatusChanged(orderId, oldStatus, OrderStatus.WAITING_FINAL_FEED, "early exercise", block.timestamp);
    }

    /**
     * @notice 买方取消未成交的RFQ
     */
    function cancelRFQ(uint256 orderId) external override 
        validOrder(orderId) 
        onlyBuyer(orderId) 
        nonReentrant 
        whenNotPaused 
    {
        Order storage order = orders[orderId];
        require(
            order.status == OrderStatus.RFQ_CREATED || order.status == OrderStatus.QUOTING,
            "OptionsCore: cannot cancel after match"
        );

        OrderStatus oldStatus = order.status;
        order.status = OrderStatus.CANCELLED;

        // 注意：建仓手续费不退还

        emit OrderCancelled(orderId, "buyer cancelled", block.timestamp);
        emit OrderStatusChanged(orderId, oldStatus, OrderStatus.CANCELLED, "buyer cancelled", block.timestamp);
    }

    // ==================== 卖方功能实现 ====================

    /**
     * @notice 卖方创建卖单
     */
    function createSellerOrder(
        string calldata underlyingName,
        string calldata underlyingCode,
        string calldata market,
        string calldata country,
        string calldata refPrice,
        Direction direction,
        uint256 notionalUSDT,
        uint256 expiryTimestamp,
        uint256 premiumRate,
        uint256 marginAmount,
        LiquidationRule liquidationRule,
        uint8 consecutiveDays,
        uint8 dailyLimitPercent,
        uint256 arbitrationWindow,
        bool dividendAdjustment
    ) external override nonReentrant whenNotPaused returns (uint256 orderId) {
        require(notionalUSDT > 0, "OptionsCore: notional must be positive");
        require(expiryTimestamp > block.timestamp, "OptionsCore: expiry must be in future");

        // 收取建仓手续费 1U
        usdt.safeTransferFrom(msg.sender, address(vaultManager), config.creationFee());
        
        // 收取保证金
        if (marginAmount > 0) {
            usdt.safeTransferFrom(msg.sender, address(vaultManager), marginAmount);
        }
        
        orderId = nextOrderId++;

        Order storage order = orders[orderId];
        order.orderId = orderId;
        order.seller = msg.sender;
        order.underlyingName = underlyingName;
        order.underlyingCode = underlyingCode;
        order.market = market;
        order.country = country;
        order.refPrice = refPrice;
        order.direction = direction;
        order.notionalUSDT = notionalUSDT;
        order.expiryTimestamp = expiryTimestamp;
        order.premiumRate = premiumRate;
        order.premiumAmount = (notionalUSDT * premiumRate) / 10000;
        order.initialMargin = marginAmount;
        order.currentMargin = marginAmount;
        order.liquidationRule = liquidationRule;
        order.consecutiveDays = consecutiveDays;
        order.dailyLimitPercent = dailyLimitPercent;
        order.arbitrationWindow = arbitrationWindow;
        order.dividendAdjustment = dividendAdjustment;
        order.status = OrderStatus.RFQ_CREATED;
        order.createdAt = block.timestamp;

        // 添加到卖方订单列表
        sellerOrders[msg.sender].push(orderId);

        // 添加到检索索引
        ordersByCountry[country].push(orderId);
        ordersByMarket[market].push(orderId);
        ordersByCode[underlyingCode].push(orderId);

        emit OrderCreated(orderId, msg.sender, false, block.timestamp);

        return orderId;
    }

    /**
     * @notice 卖方对买方RFQ报价
     */
    function submitQuote(
        uint256 orderId,
        uint256 premiumRate,
        uint256 marginRate,
        LiquidationRule liquidationRule,
        uint8 consecutiveDays,
        uint8 dailyLimitPercent
    ) external override validOrder(orderId) nonReentrant whenNotPaused returns (uint256 quoteId) {
        Order storage order = orders[orderId];
        require(
            order.status == OrderStatus.RFQ_CREATED || order.status == OrderStatus.QUOTING,
            "OptionsCore: order not accepting quotes"
        );
        require(order.buyer != address(0), "OptionsCore: not a buyer order");
        require(block.timestamp < order.createdAt + config.rfqValidityPeriod(), "OptionsCore: RFQ expired");

        // 检查报价数量限制
        require(
            orderQuotes[orderId].length < config.maxQuotesPerBuyerOrder(),
            "OptionsCore: max quotes reached"
        );

        // 检查卖方类型
        if (order.sellerType == SellerType.DesignatedSeller) {
            require(msg.sender == order.designatedSeller, "OptionsCore: not designated seller");
        }

        // 计算保证金金额
        uint256 marginAmount = (order.notionalUSDT * marginRate) / 10000;
        require(marginRate >= order.minMarginRate, "OptionsCore: margin rate too low");

        // 收取保证金
        usdt.safeTransferFrom(msg.sender, address(vaultManager), marginAmount);

        quoteId = nextQuoteId++;

        Quote memory quote = Quote({
            quoteId: quoteId,
            orderId: orderId,
            seller: msg.sender,
            sellerType: SellerType.FreeSeller,  // TODO: 根据实际情况判断
            premiumRate: premiumRate,
            premiumAmount: (order.notionalUSDT * premiumRate) / 10000,
            marginRate: marginRate,
            marginAmount: marginAmount,
            liquidationRule: liquidationRule,
            consecutiveDays: consecutiveDays,
            dailyLimitPercent: dailyLimitPercent,
            createdAt: block.timestamp,
            expiresAt: block.timestamp + config.quoteValidityPeriod(),
            status: QuoteStatus.Active
        });

        quotes[quoteId] = quote;
        orderQuotes[orderId].push(quote);

        // 更新订单状态为报价中
        if (order.status == OrderStatus.RFQ_CREATED) {
            order.status = OrderStatus.QUOTING;
        }

        emit QuoteSubmitted(orderId, quoteId, msg.sender, premiumRate, block.timestamp);

        return quoteId;
    }

    /**
     * @notice 卖方追加保证金
     */
    function addMargin(uint256 orderId, uint256 amount) external override 
        validOrder(orderId) 
        onlySeller(orderId) 
        nonReentrant 
        whenNotPaused 
    {
        require(amount > 0, "OptionsCore: amount must be positive");
        
        Order storage order = orders[orderId];
        require(order.status == OrderStatus.LIVE, "OptionsCore: order not live");

        uint256 oldMargin = order.currentMargin;
        usdt.safeTransferFrom(msg.sender, address(vaultManager), amount);
        order.currentMargin += amount;

        emit MarginChanged(orderId, msg.sender, oldMargin, order.currentMargin, "add", block.timestamp);
    }

    /**
     * @notice 卖方提取超额保证金（不能低于初始保证金）
     */
    function withdrawExcessMargin(uint256 orderId, uint256 amount) external override 
        validOrder(orderId) 
        onlySeller(orderId) 
        nonReentrant 
        whenNotPaused 
    {
        Order storage order = orders[orderId];
        require(order.status == OrderStatus.LIVE, "OptionsCore: order not live");
        
        uint256 excess = order.currentMargin - order.initialMargin;
        require(amount <= excess, "OptionsCore: cannot withdraw below initial margin");

        uint256 oldMargin = order.currentMargin;
        order.currentMargin -= amount;
        
        // 通过 VaultManager 提取
        vaultManager.withdrawMargin(msg.sender, address(usdt), amount);

        emit MarginChanged(orderId, msg.sender, oldMargin, order.currentMargin, "withdraw", block.timestamp);
    }

    // ==================== 结算功能实现 ====================

    /**
     * @notice 到期结算
     */
    function settle(uint256 orderId) external override 
        validOrder(orderId) 
        nonReentrant 
        whenNotPaused 
    {
        Order storage order = orders[orderId];
        require(order.status == OrderStatus.PENDING_SETTLEMENT, "OptionsCore: not pending settlement");

        // 计算盈亏
        // TODO: 实现具体结算逻辑

        OrderStatus oldStatus = order.status;
        order.status = OrderStatus.SETTLED;
        order.settledAt = block.timestamp;

        emit OrderSettled(orderId, 0, 0, block.timestamp);
        emit OrderStatusChanged(orderId, oldStatus, OrderStatus.SETTLED, "settled", block.timestamp);
    }

    /**
     * @notice 发起仲裁
     */
    function initiateArbitration(uint256 orderId) external payable override 
        validOrder(orderId) 
        nonReentrant 
        whenNotPaused 
    {
        Order storage order = orders[orderId];
        require(
            order.status == OrderStatus.PENDING_SETTLEMENT,
            "OptionsCore: cannot initiate arbitration"
        );
        require(
            msg.sender == order.buyer || msg.sender == order.seller,
            "OptionsCore: not party to order"
        );
        require(
            block.timestamp <= order.settledAt + order.arbitrationWindow,
            "OptionsCore: arbitration window closed"
        );

        // 收取仲裁费 30U
        usdt.safeTransferFrom(msg.sender, address(vaultManager), config.arbitrationFee());

        OrderStatus oldStatus = order.status;
        order.status = OrderStatus.ARBITRATION;

        emit OrderStatusChanged(orderId, oldStatus, OrderStatus.ARBITRATION, "arbitration initiated", block.timestamp);
    }

    /**
     * @notice 强制清算（保证金不足）
     */
    function forceLiquidate(uint256 orderId) external override 
        validOrder(orderId) 
        nonReentrant 
        whenNotPaused 
    {
        Order storage order = orders[orderId];
        require(order.status == OrderStatus.LIVE, "OptionsCore: order not live");

        // TODO: 检查保证金是否充足

        OrderStatus oldStatus = order.status;
        order.status = OrderStatus.LIQUIDATED;
        order.settledAt = block.timestamp;

        emit OrderLiquidated(orderId, order.buyer, order.currentMargin, block.timestamp);
        emit OrderStatusChanged(orderId, oldStatus, OrderStatus.LIQUIDATED, "force liquidated", block.timestamp);
    }

    // ==================== 查询功能实现 ====================

    function getOrder(uint256 orderId) external view override returns (Order memory) {
        return orders[orderId];
    }

    function getQuotes(uint256 orderId) external view override returns (Quote[] memory) {
        return orderQuotes[orderId];
    }

    function getBuyerOrders(address buyer) external view override returns (uint256[] memory) {
        return buyerOrders[buyer];
    }

    function getSellerOrders(address seller) external view override returns (uint256[] memory) {
        return sellerOrders[seller];
    }

    /**
     * @notice 按国家检索订单
     */
    function getOrdersByCountry(string calldata country) external view returns (uint256[] memory) {
        return ordersByCountry[country];
    }

    /**
     * @notice 按市场检索订单
     */
    function getOrdersByMarket(string calldata market) external view returns (uint256[] memory) {
        return ordersByMarket[market];
    }

    // ==================== 管理功能 ====================

    function setConfig(address _config) external onlyRole(DEFAULT_ADMIN_ROLE) {
        config = Config(_config);
    }

    function setVaultManager(address _vaultManager) external onlyRole(DEFAULT_ADMIN_ROLE) {
        vaultManager = VaultManager(_vaultManager);
    }

    function pause() external onlyRole(DEFAULT_ADMIN_ROLE) {
        _pause();
    }

    function unpause() external onlyRole(DEFAULT_ADMIN_ROLE) {
        _unpause();
    }
}

contracts/feed/FeedProtocol.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "@openzeppelin/contracts/token/ERC20/IERC20.sol";
import "@openzeppelin/contracts/token/ERC20/utils/SafeERC20.sol";
import "@openzeppelin/contracts/access/AccessControl.sol";
import "@openzeppelin/contracts/utils/ReentrancyGuard.sol";
import "@openzeppelin/contracts/utils/Pausable.sol";
import "../libraries/NSTTypes.sol";
import "../interfaces/IFeedProtocol.sol";
import "../core/Config.sol";

/**
 * @title FeedProtocol
 * @notice 独立喂价协议 - 喂价请求、喂价提交、结果聚合
 * @dev 与期权协议完全分离，可服务于多种协议
 */
contract FeedProtocol is IFeedProtocol, AccessControl, ReentrancyGuard, Pausable {
    using SafeERC20 for IERC20;

    // ==================== 角色定义 ====================
    bytes32 public constant FEED_OPERATOR_ROLE = keccak256("FEED_OPERATOR_ROLE");
    bytes32 public constant PROTOCOL_ROLE = keccak256("PROTOCOL_ROLE");  // 可调用的协议合约
    bytes32 public constant SENIOR_FEEDER_ROLE = keccak256("SENIOR_FEEDER_ROLE");  // 高级喂价员（仲裁用）

    // ==================== 状态变量 ====================
    Config public config;
    IERC20 public usdt;

    uint256 public nextRequestId = 1;

    // 喂价请求存储
    mapping(uint256 => FeedRequest) public feedRequests;
    
    // 喂价请求的提交记录
    struct FeedSubmission {
        address feeder;
        uint256 price;
        uint256 timestamp;
        bool isValid;
    }
    mapping(uint256 => FeedSubmission[]) public requestSubmissions;
    mapping(uint256 => mapping(address => bool)) public hasSubmitted;

    // 喂价员注册
    struct Feeder {
        address feederAddress;
        uint256 stakedAmount;
        uint256 completedFeeds;
        uint256 rejectedFeeds;
        uint256 registeredAt;
        bool isActive;
        bool isBlacklisted;
    }
    mapping(address => Feeder) public feeders;
    address[] public feederList;

    // 喂价档位配置
    struct FeedTierConfig {
        uint8 totalFeeders;
        uint8 effectiveFeeds;
        uint256 platformFee;
        uint256 feederReward;
        uint256 totalFee;
    }
    mapping(FeedTier => FeedTierConfig) public tierConfigs;

    // 订单关联的喂价请求
    mapping(uint256 => uint256[]) public orderFeedRequests;

    // ==================== 事件 ====================
    event FeederRegistered(
        address indexed feeder,
        uint256 stakedAmount,
        uint256 timestamp
    );

    event FeederDeactivated(
        address indexed feeder,
        string reason,
        uint256 timestamp
    );

    event FeederBlacklisted(
        address indexed feeder,
        string reason,
        uint256 timestamp
    );

    event RewardDistributed(
        uint256 indexed requestId,
        address indexed feeder,
        uint256 amount,
        uint256 timestamp
    );

    // ==================== 构造函数 ====================
    constructor(
        address _config,
        address _usdt,
        address _admin
    ) {
        config = Config(_config);
        usdt = IERC20(_usdt);
        
        _grantRole(DEFAULT_ADMIN_ROLE, _admin);
        _grantRole(FEED_OPERATOR_ROLE, _admin);

        // 初始化喂价档位配置
        _initTierConfigs();
    }

    function _initTierConfigs() internal {
        // 5-3档：3U
        tierConfigs[FeedTier.Tier_5_3] = FeedTierConfig({
            totalFeeders: 5,
            effectiveFeeds: 3,
            platformFee: 0.3 ether,     // 10% = 0.3U
            feederReward: 2.7 ether,    // 90% = 2.7U
            totalFee: 3 ether
        });

        // 7-5档：5U
        tierConfigs[FeedTier.Tier_7_5] = FeedTierConfig({
            totalFeeders: 7,
            effectiveFeeds: 5,
            platformFee: 0.5 ether,
            feederReward: 4.5 ether,
            totalFee: 5 ether
        });

        // 10-7档：8U
        tierConfigs[FeedTier.Tier_10_7] = FeedTierConfig({
            totalFeeders: 10,
            effectiveFeeds: 7,
            platformFee: 0.8 ether,
            feederReward: 7.2 ether,
            totalFee: 8 ether
        });
    }

    // ==================== 修改器 ====================
    modifier onlyOperator() {
        require(hasRole(FEED_OPERATOR_ROLE, msg.sender), "FeedProtocol: not operator");
        _;
    }

    modifier onlyProtocol() {
        require(hasRole(PROTOCOL_ROLE, msg.sender), "FeedProtocol: not authorized protocol");
        _;
    }

    modifier onlyActiveFeeder() {
        require(feeders[msg.sender].isActive, "FeedProtocol: not active feeder");
        require(!feeders[msg.sender].isBlacklisted, "FeedProtocol: feeder blacklisted");
        require(
            feeders[msg.sender].stakedAmount >= config.minFeederStake(),
            "FeedProtocol: insufficient stake"
        );
        _;
    }

    modifier validRequest(uint256 requestId) {
        require(requestId > 0 && requestId < nextRequestId, "FeedProtocol: invalid request");
        _;
    }

    // ==================== 喂价员注册 ====================

    /**
     * @notice 注册为喂价员
     * @param stakeAmount 质押金额（最低100U）
     */
    function registerFeeder(uint256 stakeAmount) external nonReentrant whenNotPaused {
        require(feeders[msg.sender].feederAddress == address(0), "FeedProtocol: already registered");
        require(stakeAmount >= config.minFeederStake(), "FeedProtocol: insufficient stake");

        usdt.safeTransferFrom(msg.sender, address(this), stakeAmount);

        feeders[msg.sender] = Feeder({
            feederAddress: msg.sender,
            stakedAmount: stakeAmount,
            completedFeeds: 0,
            rejectedFeeds: 0,
            registeredAt: block.timestamp,
            isActive: true,
            isBlacklisted: false
        });

        feederList.push(msg.sender);

        emit FeederRegistered(msg.sender, stakeAmount, block.timestamp);
    }

    /**
     * @notice 追加质押
     */
    function addStake(uint256 amount) external nonReentrant whenNotPaused {
        require(feeders[msg.sender].feederAddress != address(0), "FeedProtocol: not registered");
        
        usdt.safeTransferFrom(msg.sender, address(this), amount);
        feeders[msg.sender].stakedAmount += amount;
    }

    /**
     * @notice 提取质押（需无进行中的喂价任务）
     */
    function withdrawStake(uint256 amount) external nonReentrant whenNotPaused {
        Feeder storage feeder = feeders[msg.sender];
        require(feeder.stakedAmount >= amount, "FeedProtocol: insufficient stake");
        require(
            feeder.stakedAmount - amount >= config.minFeederStake() || amount == feeder.stakedAmount,
            "FeedProtocol: must maintain min stake or withdraw all"
        );

        feeder.stakedAmount -= amount;
        if (feeder.stakedAmount == 0) {
            feeder.isActive = false;
        }
        
        usdt.safeTransfer(msg.sender, amount);
    }

    // ==================== 喂价请求 ====================

    /**
     * @notice 创建喂价请求（由期权协议调用）
     */
    function createFeedRequest(
        uint256 orderId,
        FeedType feedType,
        FeedTier tier
    ) external payable override onlyProtocol nonReentrant returns (uint256 requestId) {
        FeedTierConfig memory tierConfig = tierConfigs[tier];
        
        // 收取喂价费用
        usdt.safeTransferFrom(msg.sender, address(this), tierConfig.totalFee);

        requestId = nextRequestId++;

        feedRequests[requestId] = FeedRequest({
            requestId: requestId,
            orderId: orderId,
            feedType: feedType,
            tier: tier,
            deadline: block.timestamp + 30 minutes,  // 30分钟超时
            createdAt: block.timestamp,
            totalFeeders: tierConfig.totalFeeders,
            submittedCount: 0,
            finalPrice: 0,
            finalized: false
        });

        orderFeedRequests[orderId].push(requestId);

        // 注意：实际的喂价员选择需要 VRF 随机数
        // 这里简化处理，事件触发后由链下服务分配

        emit FeedRequested(
            requestId,
            orderId,
            "",  // underlyingName 需要从订单获取
            "",  // underlyingCode
            "",  // market
            "",  // country
            feedType,
            LiquidationRule.NoLiquidation,
            0,   // consecutiveDays
            0,   // exerciseDelay
            block.timestamp
        );

        return requestId;
    }

    /**
     * @notice 喂价员提交喂价
     */
    function submitFeed(
        uint256 requestId,
        uint256 price
    ) external override validRequest(requestId) onlyActiveFeeder nonReentrant whenNotPaused {
        FeedRequest storage request = feedRequests[requestId];
        require(!request.finalized, "FeedProtocol: already finalized");
        require(block.timestamp <= request.deadline, "FeedProtocol: request expired");
        require(!hasSubmitted[requestId][msg.sender], "FeedProtocol: already submitted");
        require(price > 0, "FeedProtocol: price must be positive");

        hasSubmitted[requestId][msg.sender] = true;
        request.submittedCount++;

        requestSubmissions[requestId].push(FeedSubmission({
            feeder: msg.sender,
            price: price,
            timestamp: block.timestamp,
            isValid: true
        }));

        emit FeedSubmitted(requestId, msg.sender, price, block.timestamp);

        // 检查是否达到所需数量
        if (request.submittedCount >= request.totalFeeders) {
            _finalizeFeed(requestId);
        }
    }

    /**
     * @notice 喂价员拒绝喂价
     */
    function rejectFeed(
        uint256 requestId,
        string calldata reason
    ) external override validRequest(requestId) onlyActiveFeeder nonReentrant whenNotPaused {
        FeedRequest storage request = feedRequests[requestId];
        require(!request.finalized, "FeedProtocol: already finalized");
        require(!hasSubmitted[requestId][msg.sender], "FeedProtocol: already submitted");

        hasSubmitted[requestId][msg.sender] = true;
        feeders[msg.sender].rejectedFeeds++;

        emit FeedRejected(requestId, msg.sender, reason, block.timestamp);
    }

    /**
     * @notice 完成喂价聚合（取中间位）
     */
    function finalizeFeed(uint256 requestId) external override returns (uint256 finalPrice) {
        return _finalizeFeed(requestId);
    }

    function _finalizeFeed(uint256 requestId) internal returns (uint256 finalPrice) {
        FeedRequest storage request = feedRequests[requestId];
        require(!request.finalized, "FeedProtocol: already finalized");

        FeedSubmission[] storage submissions = requestSubmissions[requestId];
        require(submissions.length > 0, "FeedProtocol: no submissions");

        // 收集有效价格
        uint256[] memory prices = new uint256[](submissions.length);
        uint256 validCount = 0;
        
        for (uint256 i = 0; i < submissions.length; i++) {
            if (submissions[i].isValid && submissions[i].price > 0) {
                prices[validCount] = submissions[i].price;
                validCount++;
            }
        }

        require(validCount > 0, "FeedProtocol: no valid prices");

        // 排序价格
        for (uint256 i = 0; i < validCount - 1; i++) {
            for (uint256 j = 0; j < validCount - i - 1; j++) {
                if (prices[j] > prices[j + 1]) {
                    uint256 temp = prices[j];
                    prices[j] = prices[j + 1];
                    prices[j + 1] = temp;
                }
            }
        }

        // 取中位数
        if (validCount % 2 == 0) {
            finalPrice = (prices[validCount / 2 - 1] + prices[validCount / 2]) / 2;
        } else {
            finalPrice = prices[validCount / 2];
        }

        request.finalPrice = finalPrice;
        request.finalized = true;

        // 分发奖励
        _distributeRewards(requestId, submissions);

        emit FeedFinalized(requestId, finalPrice, block.timestamp);

        return finalPrice;
    }

    /**
     * @notice 分发喂价奖励
     */
    function _distributeRewards(uint256 requestId, FeedSubmission[] storage submissions) internal {
        FeedRequest storage request = feedRequests[requestId];
        FeedTierConfig memory tierConfig = tierConfigs[request.tier];
        
        uint256 rewardPerFeeder = tierConfig.feederReward / submissions.length;

        for (uint256 i = 0; i < submissions.length; i++) {
            if (submissions[i].isValid) {
                address feeder = submissions[i].feeder;
                usdt.safeTransfer(feeder, rewardPerFeeder);
                feeders[feeder].completedFeeds++;
                
                emit RewardDistributed(requestId, feeder, rewardPerFeeder, block.timestamp);
            }
        }

        // 平台费用保留在合约中
    }

    // ==================== 查询功能 ====================

    function getFeedFee(FeedTier tier) external view override returns (uint256) {
        return tierConfigs[tier].totalFee;
    }

    function getFeedRequest(uint256 requestId) external view returns (FeedRequest memory) {
        return feedRequests[requestId];
    }

    function getFeeder(address feeder) external view returns (Feeder memory) {
        return feeders[feeder];
    }

    function getFeederCount() external view returns (uint256) {
        return feederList.length;
    }

    function getOrderFeedRequests(uint256 orderId) external view returns (uint256[] memory) {
        return orderFeedRequests[orderId];
    }

    function getSubmissions(uint256 requestId) external view returns (FeedSubmission[] memory) {
        return requestSubmissions[requestId];
    }

    // ==================== 管理功能 ====================

    function grantProtocolRole(address protocol) external onlyRole(DEFAULT_ADMIN_ROLE) {
        grantRole(PROTOCOL_ROLE, protocol);
    }

    function grantSeniorFeederRole(address feeder) external onlyRole(DEFAULT_ADMIN_ROLE) {
        grantRole(SENIOR_FEEDER_ROLE, feeder);
    }

    function blacklistFeeder(address feeder, string calldata reason) external onlyOperator {
        feeders[feeder].isBlacklisted = true;
        feeders[feeder].isActive = false;
        emit FeederBlacklisted(feeder, reason, block.timestamp);
    }

    function setConfig(address _config) external onlyRole(DEFAULT_ADMIN_ROLE) {
        config = Config(_config);
    }

    function withdrawPlatformFees(address to) external onlyRole(DEFAULT_ADMIN_ROLE) {
        // 提取平台费用
        uint256 balance = usdt.balanceOf(address(this));
        // 需要减去所有质押金额
        uint256 totalStaked = 0;
        for (uint256 i = 0; i < feederList.length; i++) {
            totalStaked += feeders[feederList[i]].stakedAmount;
        }
        uint256 platformFees = balance > totalStaked ? balance - totalStaked : 0;
        if (platformFees > 0) {
            usdt.safeTransfer(to, platformFees);
        }
    }

    function pause() external onlyRole(DEFAULT_ADMIN_ROLE) {
        _pause();
    }

    function unpause() external onlyRole(DEFAULT_ADMIN_ROLE) {
        _unpause();
    }
}

contracts/feed/VolumeBasedFeed.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "@openzeppelin/contracts/token/ERC20/IERC20.sol";
import "@openzeppelin/contracts/token/ERC20/utils/SafeERC20.sol";
import "@openzeppelin/contracts/access/AccessControl.sol";
import "@openzeppelin/contracts/utils/ReentrancyGuard.sol";
import "@openzeppelin/contracts/utils/Pausable.sol";
import "../libraries/NSTTypes.sol";
import "../core/Config.sol";

/**
 * @title VolumeBasedFeed
 * @notice 跟量成交喂价合约 - 需要真实市场成交量支持的喂价方式
 * @dev 卖方提交建议价格，喂价员验证后确认/修正/拒绝
 */
contract VolumeBasedFeed is AccessControl, ReentrancyGuard, Pausable {
    using SafeERC20 for IERC20;

    // ==================== 角色定义 ====================
    bytes32 public constant FEED_OPERATOR_ROLE = keccak256("FEED_OPERATOR_ROLE");
    bytes32 public constant PROTOCOL_ROLE = keccak256("PROTOCOL_ROLE");
    bytes32 public constant FEEDER_ROLE = keccak256("FEEDER_ROLE");

    // ==================== 数据结构 ====================
    
    /// @notice 跟量成交喂价请求状态
    enum VolumeBasedFeedStatus {
        Pending,        // 待验证
        Approved,       // 验证通过，价格合理
        Rejected,       // 验证拒绝，价格不合理或无成交量
        Modified,       // 喂价员修正价格
        Expired,        // 已过期
        Finalized       // 已完成
    }

    /// @notice 拒绝原因
    enum RejectReason {
        T_PLUS_X_NOT_MET,       // 不符合T+X行权条件
        NO_TRADING_VOLUME,      // 跟量成交无成交量
        MARKET_CLOSED,          // 市场休市
        PRICE_NOT_AVAILABLE,    // 无法获取价格
        PRICE_UNREASONABLE,     // 价格不合理
        OTHER                   // 其他原因
    }

    /// @notice 跟量成交喂价请求
    struct VolumeBasedFeedRequest {
        uint256 requestId;
        uint256 orderId;
        address seller;                 // 卖方地址
        uint256 suggestedPrice;         // 卖方建议成交价格
        string priceEvidence;           // 价格依据说明
        uint256 submittedAt;            // 提交时间
        uint256 deadline;               // 验证截止时间
        
        // 验证结果
        bool isVerified;                // 是否已验证
        address verifiedBy;             // 验证的喂价员地址
        uint256 finalPrice;             // 最终确认价格
        VolumeBasedFeedStatus status;
        
        // 拒绝信息
        RejectReason rejectReason;
        string rejectDescription;       // 拒绝详细说明
        
        // 喂价类型
        FeedType feedType;              // 期初/期末/动态
        bool isInitialFeed;             // 是否为期初喂价（拒绝则取消订单）
    }

    // ==================== 状态变量 ====================
    Config public config;
    IERC20 public usdt;

    uint256 public nextRequestId = 1;

    // 请求存储
    mapping(uint256 => VolumeBasedFeedRequest) public requests;
    
    // 订单关联的跟量成交请求
    mapping(uint256 => uint256[]) public orderVolumeRequests;

    // 验证超时时间（默认30分钟）
    uint256 public verificationTimeout = 30 minutes;

    // ==================== 事件 ====================
    
    /// @notice 卖方提交建议价格
    event SuggestedPriceSubmitted(
        uint256 indexed requestId,
        uint256 indexed orderId,
        address indexed seller,
        uint256 suggestedPrice,
        string priceEvidence,
        FeedType feedType,
        uint256 timestamp
    );

    /// @notice 喂价员验证通过
    event PriceApproved(
        uint256 indexed requestId,
        address indexed feeder,
        uint256 finalPrice,
        uint256 timestamp
    );

    /// @notice 喂价员修正价格
    event PriceModified(
        uint256 indexed requestId,
        address indexed feeder,
        uint256 originalPrice,
        uint256 modifiedPrice,
        string reason,
        uint256 timestamp
    );

    /// @notice 喂价员拒绝
    event PriceRejected(
        uint256 indexed requestId,
        address indexed feeder,
        RejectReason reason,
        string description,
        uint256 timestamp
    );

    /// @notice 请求超时
    event RequestExpired(
        uint256 indexed requestId,
        uint256 timestamp
    );

    /// @notice 重新喂价（平仓订单拒绝后）
    event RefeedRequired(
        uint256 indexed requestId,
        uint256 indexed orderId,
        string reason,
        uint256 timestamp
    );

    // ==================== 构造函数 ====================
    constructor(
        address _config,
        address _usdt,
        address _admin
    ) {
        config = Config(_config);
        usdt = IERC20(_usdt);
        
        _grantRole(DEFAULT_ADMIN_ROLE, _admin);
        _grantRole(FEED_OPERATOR_ROLE, _admin);
    }

    // ==================== 修改器 ====================
    modifier onlyOperator() {
        require(hasRole(FEED_OPERATOR_ROLE, msg.sender), "VolumeBasedFeed: not operator");
        _;
    }

    modifier onlyProtocol() {
        require(hasRole(PROTOCOL_ROLE, msg.sender), "VolumeBasedFeed: not authorized protocol");
        _;
    }

    modifier onlyFeeder() {
        require(hasRole(FEEDER_ROLE, msg.sender), "VolumeBasedFeed: not authorized feeder");
        _;
    }

    modifier validRequest(uint256 requestId) {
        require(requestId > 0 && requestId < nextRequestId, "VolumeBasedFeed: invalid request");
        _;
    }

    modifier requestPending(uint256 requestId) {
        require(
            requests[requestId].status == VolumeBasedFeedStatus.Pending,
            "VolumeBasedFeed: request not pending"
        );
        _;
    }

    // ==================== 卖方功能 ====================

    /**
     * @notice 卖方提交建议价格
     * @param orderId 订单ID
     * @param suggestedPrice 建议成交价格
     * @param priceEvidence 价格依据说明（如：上海黄金交易所实时成交价）
     * @param feedType 喂价类型
     * @param isInitialFeed 是否为期初喂价
     */
    function submitSuggestedPrice(
        uint256 orderId,
        uint256 suggestedPrice,
        string calldata priceEvidence,
        FeedType feedType,
        bool isInitialFeed
    ) external nonReentrant whenNotPaused returns (uint256 requestId) {
        require(suggestedPrice > 0, "VolumeBasedFeed: price must be positive");
        require(bytes(priceEvidence).length > 0, "VolumeBasedFeed: evidence required");

        requestId = nextRequestId++;

        requests[requestId] = VolumeBasedFeedRequest({
            requestId: requestId,
            orderId: orderId,
            seller: msg.sender,
            suggestedPrice: suggestedPrice,
            priceEvidence: priceEvidence,
            submittedAt: block.timestamp,
            deadline: block.timestamp + verificationTimeout,
            isVerified: false,
            verifiedBy: address(0),
            finalPrice: 0,
            status: VolumeBasedFeedStatus.Pending,
            rejectReason: RejectReason.OTHER,
            rejectDescription: "",
            feedType: feedType,
            isInitialFeed: isInitialFeed
        });

        orderVolumeRequests[orderId].push(requestId);

        emit SuggestedPriceSubmitted(
            requestId,
            orderId,
            msg.sender,
            suggestedPrice,
            priceEvidence,
            feedType,
            block.timestamp
        );

        return requestId;
    }

    // ==================== 喂价员功能 ====================

    /**
     * @notice 喂价员验证通过，确认使用卖方建议价格
     * @param requestId 请求ID
     */
    function approvePrice(uint256 requestId) 
        external 
        validRequest(requestId) 
        requestPending(requestId)
        onlyFeeder 
        nonReentrant 
        whenNotPaused 
    {
        VolumeBasedFeedRequest storage request = requests[requestId];
        require(block.timestamp <= request.deadline, "VolumeBasedFeed: request expired");

        request.isVerified = true;
        request.verifiedBy = msg.sender;
        request.finalPrice = request.suggestedPrice;
        request.status = VolumeBasedFeedStatus.Approved;

        emit PriceApproved(requestId, msg.sender, request.finalPrice, block.timestamp);
    }

    /**
     * @notice 喂价员修正价格
     * @param requestId 请求ID
     * @param modifiedPrice 修正后的价格
     * @param reason 修正原因
     */
    function modifyPrice(
        uint256 requestId,
        uint256 modifiedPrice,
        string calldata reason
    ) 
        external 
        validRequest(requestId) 
        requestPending(requestId)
        onlyFeeder 
        nonReentrant 
        whenNotPaused 
    {
        require(modifiedPrice > 0, "VolumeBasedFeed: price must be positive");
        require(bytes(reason).length > 0, "VolumeBasedFeed: reason required");

        VolumeBasedFeedRequest storage request = requests[requestId];
        require(block.timestamp <= request.deadline, "VolumeBasedFeed: request expired");

        uint256 originalPrice = request.suggestedPrice;

        request.isVerified = true;
        request.verifiedBy = msg.sender;
        request.finalPrice = modifiedPrice;
        request.status = VolumeBasedFeedStatus.Modified;

        emit PriceModified(
            requestId,
            msg.sender,
            originalPrice,
            modifiedPrice,
            reason,
            block.timestamp
        );
    }

    /**
     * @notice 喂价员拒绝喂价
     * @param requestId 请求ID
     * @param reason 拒绝原因枚举
     * @param description 详细说明
     */
    function rejectPrice(
        uint256 requestId,
        RejectReason reason,
        string calldata description
    ) 
        external 
        validRequest(requestId) 
        requestPending(requestId)
        onlyFeeder 
        nonReentrant 
        whenNotPaused 
    {
        VolumeBasedFeedRequest storage request = requests[requestId];
        require(block.timestamp <= request.deadline, "VolumeBasedFeed: request expired");

        request.isVerified = true;
        request.verifiedBy = msg.sender;
        request.status = VolumeBasedFeedStatus.Rejected;
        request.rejectReason = reason;
        request.rejectDescription = description;

        emit PriceRejected(requestId, msg.sender, reason, description, block.timestamp);

        // 根据喂价类型处理拒绝后的逻辑
        if (request.isInitialFeed) {
            // 期初订单被拒绝 -> 订单将被自动取消（由 OptionsCore 处理）
        } else {
            // 平仓订单被拒绝 -> 需要重新喂价（改为正常喂价）
            emit RefeedRequired(
                requestId,
                request.orderId,
                "Volume-based feed rejected, requires normal feed",
                block.timestamp
            );
        }
    }

    // ==================== 超时处理 ====================

    /**
     * @notice 标记请求为超时
     * @param requestId 请求ID
     */
    function markExpired(uint256 requestId) 
        external 
        validRequest(requestId) 
        requestPending(requestId)
    {
        VolumeBasedFeedRequest storage request = requests[requestId];
        require(block.timestamp > request.deadline, "VolumeBasedFeed: not expired yet");

        request.status = VolumeBasedFeedStatus.Expired;

        emit RequestExpired(requestId, block.timestamp);
    }

    // ==================== 查询功能 ====================

    /**
     * @notice 获取请求详情
     */
    function getRequest(uint256 requestId) external view returns (VolumeBasedFeedRequest memory) {
        return requests[requestId];
    }

    /**
     * @notice 获取订单的所有跟量成交请求
     */
    function getOrderVolumeRequests(uint256 orderId) external view returns (uint256[] memory) {
        return orderVolumeRequests[orderId];
    }

    /**
     * @notice 获取请求的最终价格（如果已完成）
     */
    function getFinalPrice(uint256 requestId) external view returns (uint256, bool) {
        VolumeBasedFeedRequest storage request = requests[requestId];
        bool isValid = request.status == VolumeBasedFeedStatus.Approved ||
                       request.status == VolumeBasedFeedStatus.Modified;
        return (request.finalPrice, isValid);
    }

    /**
     * @notice 检查请求状态
     */
    function getRequestStatus(uint256 requestId) external view returns (VolumeBasedFeedStatus) {
        return requests[requestId].status;
    }

    /**
     * @notice 检查请求是否已过期
     */
    function isExpired(uint256 requestId) external view returns (bool) {
        VolumeBasedFeedRequest storage request = requests[requestId];
        return block.timestamp > request.deadline && 
               request.status == VolumeBasedFeedStatus.Pending;
    }

    /**
     * @notice 获取拒绝原因的字符串描述
     */
    function getRejectReasonString(RejectReason reason) external pure returns (string memory) {
        if (reason == RejectReason.T_PLUS_X_NOT_MET) return "T+X condition not met";
        if (reason == RejectReason.NO_TRADING_VOLUME) return "No trading volume available";
        if (reason == RejectReason.MARKET_CLOSED) return "Market is closed";
        if (reason == RejectReason.PRICE_NOT_AVAILABLE) return "Price not available";
        if (reason == RejectReason.PRICE_UNREASONABLE) return "Price is unreasonable";
        return "Other reason";
    }

    // ==================== 管理功能 ====================

    /**
     * @notice 设置验证超时时间
     */
    function setVerificationTimeout(uint256 timeout) external onlyRole(DEFAULT_ADMIN_ROLE) {
        require(timeout >= 10 minutes && timeout <= 2 hours, "VolumeBasedFeed: invalid timeout");
        verificationTimeout = timeout;
    }

    /**
     * @notice 授权协议角色
     */
    function grantProtocolRole(address protocol) external onlyRole(DEFAULT_ADMIN_ROLE) {
        grantRole(PROTOCOL_ROLE, protocol);
    }

    /**
     * @notice 授权喂价员角色
     */
    function grantFeederRole(address feeder) external onlyRole(DEFAULT_ADMIN_ROLE) {
        grantRole(FEEDER_ROLE, feeder);
    }

    /**
     * @notice 批量授权喂价员
     */
    function grantFeederRoleBatch(address[] calldata feeders) external onlyRole(DEFAULT_ADMIN_ROLE) {
        for (uint256 i = 0; i < feeders.length; i++) {
            grantRole(FEEDER_ROLE, feeders[i]);
        }
    }

    /**
     * @notice 撤销喂价员角色
     */
    function revokeFeederRole(address feeder) external onlyRole(DEFAULT_ADMIN_ROLE) {
        revokeRole(FEEDER_ROLE, feeder);
    }

    function setConfig(address _config) external onlyRole(DEFAULT_ADMIN_ROLE) {
        config = Config(_config);
    }

    function pause() external onlyRole(DEFAULT_ADMIN_ROLE) {
        _pause();
    }

    function unpause() external onlyRole(DEFAULT_ADMIN_ROLE) {
        _unpause();
    }
}

contracts/interfaces/IFeedProtocol.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "../libraries/NSTTypes.sol";

/**
 * @title IFeedProtocol
 * @notice 喂价协议接口
 */
interface IFeedProtocol {
    // ==================== 事件 ====================
    
    /// @notice 喂价请求事件
    event FeedRequested(
        uint256 indexed requestId,
        uint256 indexed orderId,
        string underlyingName,
        string underlyingCode,
        string market,
        string country,
        FeedType feedType,
        LiquidationRule liquidationRule,
        uint8 consecutiveDays,
        uint8 exerciseDelay,
        uint256 timestamp
    );

    /// @notice 喂价提交事件
    event FeedSubmitted(
        uint256 indexed requestId,
        address indexed feeder,
        uint256 price,
        uint256 timestamp
    );

    /// @notice 喂价结果确认事件
    event FeedFinalized(
        uint256 indexed requestId,
        uint256 finalPrice,
        uint256 timestamp
    );

    /// @notice 喂价被拒绝事件
    event FeedRejected(
        uint256 indexed requestId,
        address indexed feeder,
        string reason,
        uint256 timestamp
    );

    // ==================== 函数 ====================

    /// @notice 创建喂价请求
    function createFeedRequest(
        uint256 orderId,
        FeedType feedType,
        FeedTier tier
    ) external payable returns (uint256 requestId);

    /// @notice 喂价员提交喂价
    function submitFeed(uint256 requestId, uint256 price) external;

    /// @notice 喂价员拒绝喂价
    function rejectFeed(uint256 requestId, string calldata reason) external;

    /// @notice 完成喂价聚合
    function finalizeFeed(uint256 requestId) external returns (uint256 finalPrice);

    /// @notice 获取喂价费用
    function getFeedFee(FeedTier tier) external view returns (uint256);
}

contracts/interfaces/IOptionsCore.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "../libraries/NSTTypes.sol";

/**
 * @title IOptionsCore
 * @notice 期权核心合约接口
 */
interface IOptionsCore {
    // ==================== 事件 ====================
    event OrderCreated(
        uint256 indexed orderId,
        address indexed creator,
        bool isBuyerOrder,
        uint256 timestamp
    );

    event QuoteSubmitted(
        uint256 indexed orderId,
        uint256 indexed quoteId,
        address indexed seller,
        uint256 premiumRate,
        uint256 timestamp
    );

    event OrderMatched(
        uint256 indexed orderId,
        address indexed buyer,
        address indexed seller,
        uint256 timestamp
    );

    event OrderSettled(
        uint256 indexed orderId,
        int256 buyerPnL,
        int256 sellerPnL,
        uint256 timestamp
    );

    event OrderLiquidated(
        uint256 indexed orderId,
        address beneficiary,
        uint256 amount,
        uint256 timestamp
    );

    event OrderCancelled(
        uint256 indexed orderId,
        string reason,
        uint256 timestamp
    );

    event OrderStatusChanged(
        uint256 indexed orderId,
        OrderStatus oldStatus,
        OrderStatus newStatus,
        string reason,
        uint256 timestamp
    );

    event MarginChanged(
        uint256 indexed orderId,
        address indexed seller,
        uint256 oldAmount,
        uint256 newAmount,
        string changeType,
        uint256 timestamp
    );

    // ==================== 买方功能 ====================

    /**
     * @notice 买方创建询价订单
     */
    function createBuyerRFQ(
        string calldata underlyingName,
        string calldata underlyingCode,
        string calldata market,
        string calldata country,
        string calldata refPrice,
        Direction direction,
        uint256 notionalUSDT,
        uint256 expiryTimestamp,
        uint256 maxPremiumRate,
        uint256 minMarginRate,
        SellerType acceptedSellerType,
        address designatedSeller,
        uint256 arbitrationWindow,
        uint256 marginCallDeadline,
        bool dividendAdjustment
    ) external returns (uint256 orderId);

    /**
     * @notice 买方选择卖方报价成交
     */
    function acceptQuote(uint256 quoteId) external;

    /**
     * @notice 买方发起喂价请求
     */
    function requestFeed(uint256 orderId, FeedTier tier) external payable;

    /**
     * @notice 买方提前行权
     */
    function earlyExercise(uint256 orderId) external;

    /**
     * @notice 买方取消未成交的RFQ
     */
    function cancelRFQ(uint256 orderId) external;

    // ==================== 卖方功能 ====================

    /**
     * @notice 卖方创建卖单
     */
    function createSellerOrder(
        string calldata underlyingName,
        string calldata underlyingCode,
        string calldata market,
        string calldata country,
        string calldata refPrice,
        Direction direction,
        uint256 notionalUSDT,
        uint256 expiryTimestamp,
        uint256 premiumRate,
        uint256 marginAmount,
        LiquidationRule liquidationRule,
        uint8 consecutiveDays,
        uint8 dailyLimitPercent,
        uint256 arbitrationWindow,
        bool dividendAdjustment
    ) external returns (uint256 orderId);

    /**
     * @notice 卖方对买方RFQ报价
     */
    function submitQuote(
        uint256 orderId,
        uint256 premiumRate,
        uint256 marginRate,
        LiquidationRule liquidationRule,
        uint8 consecutiveDays,
        uint8 dailyLimitPercent
    ) external returns (uint256 quoteId);

    /**
     * @notice 卖方追加保证金
     */
    function addMargin(uint256 orderId, uint256 amount) external;

    /**
     * @notice 卖方提取超额保证金
     */
    function withdrawExcessMargin(uint256 orderId, uint256 amount) external;

    // ==================== 结算功能 ====================

    /**
     * @notice 到期结算
     */
    function settle(uint256 orderId) external;

    /**
     * @notice 发起仲裁
     */
    function initiateArbitration(uint256 orderId) external payable;

    /**
     * @notice 强制清算
     */
    function forceLiquidate(uint256 orderId) external;

    // ==================== 查询功能 ====================

    function getOrder(uint256 orderId) external view returns (Order memory);
    function getQuotes(uint256 orderId) external view returns (Quote[] memory);
    function getBuyerOrders(address buyer) external view returns (uint256[] memory);
    function getSellerOrders(address seller) external view returns (uint256[] memory);
}

contracts/libraries/NSTTypes.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

/**
 * @title NSTTypes
 * @notice 数据类型定义 - NST Options MVP
 * @dev 定义所有合约共用的数据结构和枚举
 */

/**
 * @notice 订单方向
 */
enum Direction {
    Call,   // 看涨
    Put     // 看跌
}

/**
 * @notice 卖方类型
 */
enum SellerType {
    FreeSeller,         // 自由卖方
    SeatSeller,         // 席位卖方
    DesignatedSeller    // 指定卖方
}

/**
 * @notice 强平规则
 */
enum LiquidationRule {
    NoLiquidation,          // 无强平，到期结算
    ConsecutiveLimitUp,     // 连续涨停板强平（触板/封板）
    ConsecutiveDailyGain    // 连续单日涨幅≥X%强平
}

/**
 * @notice 订单状态
 */
enum OrderStatus {
    RFQ_CREATED,            // 询价已创建
    QUOTING,                // 报价中
    MATCHED,                // 已匹配，待喂价
    WAITING_INITIAL_FEED,   // 待期初喂价
    LIVE,                   // 持仓中
    WAITING_FINAL_FEED,     // 待期末喂价
    PENDING_SETTLEMENT,     // 待结算
    ARBITRATION,            // 仲裁中
    SETTLED,                // 已结算
    LIQUIDATED,             // 已强平
    CANCELLED               // 已取消
}

/**
 * @notice 报价状态
 */
enum QuoteStatus {
    Active,     // 有效
    Accepted,   // 已接受
    Rejected,   // 已拒绝
    Expired     // 已过期
}

/**
 * @notice 喂价类型
 */
enum FeedType {
    Initial,        // 期初喂价
    Dynamic,        // 动态保证金调整喂价
    Final,          // 期末喂价
    Arbitration     // 仲裁喂价
}

/**
 * @notice 喂价档位
 */
enum FeedTier {
    Tier_5_3,   // 5个喂价员，取3个有效
    Tier_7_5,   // 7个喂价员，取5个有效
    Tier_10_7   // 10个喂价员，取7个有效
}

/**
 * @notice 喂价规则
 */
enum FeedRule {
    NormalFeed,         // 正常喂价（市价）
    VolumeBasedFeed     // 跟量成交喂价（需真实成交量支持）
}

/**
 * @notice 订单结构体
 */
struct Order {
    // 基础信息
    uint256 orderId;
    address buyer;
    address seller;
    
    // 标的信息
    string underlyingName;      // 标的名称
    string underlyingCode;      // 标的代码
    string market;              // 市场
    string country;             // 国家
    string refPrice;            // 参考价格
    
    // 合约要素
    Direction direction;        // 看涨/看跌
    uint256 notionalUSDT;       // 名义本金
    uint256 strikePrice;        // 行权价
    uint256 expiryTimestamp;    // 到期时间
    
    // 费率与保证金
    uint256 premiumRate;        // 期权费率（基点）
    uint256 premiumAmount;      // 期权费金额
    uint256 initialMargin;      // 初始保证金
    uint256 currentMargin;      // 当前保证金
    uint256 minMarginRate;      // 最低保证金率（基点）
    
    // 平仓规则
    LiquidationRule liquidationRule;
    uint8 consecutiveDays;      // 连续天数
    uint8 dailyLimitPercent;    // 单日涨幅阈值
    uint8 exerciseDelay;        // T+X 行权延迟
    
    // 卖方类型
    SellerType sellerType;
    address designatedSeller;   // 指定卖方地址
    
    // 仲裁与追保配置
    uint256 arbitrationWindow;  // 仲裁窗口
    uint256 marginCallDeadline; // 追保截止时间
    
    // 分红调整
    bool dividendAdjustment;    // 是否调整行权价
    
    // 喂价规则
    FeedRule feedRule;          // 正常喂价/跟量成交喂价
    
    // 状态与时间
    OrderStatus status;
    uint256 createdAt;
    uint256 matchedAt;
    uint256 settledAt;
    uint256 lastFeedPrice;      // 最后一次喂价价格
}

/**
 * @notice 报价结构体
 */
struct Quote {
    uint256 quoteId;
    uint256 orderId;
    address seller;
    SellerType sellerType;
    
    uint256 premiumRate;        // 报价费率（基点）
    uint256 premiumAmount;      // 期权费金额
    uint256 marginRate;         // 保证金比例
    uint256 marginAmount;       // 保证金金额
    
    LiquidationRule liquidationRule;
    uint8 consecutiveDays;
    uint8 dailyLimitPercent;
    
    uint256 createdAt;
    uint256 expiresAt;          // 报价有效期
    QuoteStatus status;
}

/**
 * @notice 席位信息结构体
 */
struct Seat {
    address owner;
    uint256 depositAmount;      // 席位押金
    uint256 nstStaked;          // 质押的NST数量
    uint256 stakeStartTime;     // 质押开始时间
    uint256 currentExposure;    // 当前风险敞口
    uint256 maxExposure;        // 最大允许敞口
    bool isActive;
}

/**
 * @notice 喂价请求结构体
 */
struct FeedRequest {
    uint256 requestId;
    uint256 orderId;
    FeedType feedType;
    FeedTier tier;
    uint256 deadline;           // 喂价截止时间
    uint256 createdAt;
    uint256 totalFeeders;       // 需要的喂价员数量
    uint256 submittedCount;     // 已提交数量
    uint256 finalPrice;         // 最终价格
    bool finalized;             // 是否已完成
}

/**
 * @notice 用户积分结构体
 */
struct UserPoints {
    uint256 totalPoints;        // 累计积分
    uint256 claimedPoints;      // 已领取空投的积分
    uint256 availablePoints;    // 可用积分
    uint256 lastUpdateTime;     // 最后更新时间
}

contracts/points/PointsManager.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "@openzeppelin/contracts/token/ERC20/IERC20.sol";
import "@openzeppelin/contracts/token/ERC20/utils/SafeERC20.sol";
import "@openzeppelin/contracts/access/AccessControl.sol";
import "@openzeppelin/contracts/utils/ReentrancyGuard.sol";
import "@openzeppelin/contracts/utils/Pausable.sol";
import "../libraries/NSTTypes.sol";
import "../core/Config.sol";

/**
 * @title PointsManager
 * @notice 积分管理合约 - 手续费积分统计、空投领取
 * @dev 积分规则：1U = 100分
 */
contract PointsManager is AccessControl, ReentrancyGuard, Pausable {
    using SafeERC20 for IERC20;

    // ==================== 角色定义 ====================
    bytes32 public constant POINTS_OPERATOR_ROLE = keccak256("POINTS_OPERATOR_ROLE");
    bytes32 public constant AIRDROP_ADMIN_ROLE = keccak256("AIRDROP_ADMIN_ROLE");

    // ==================== 状态变量 ====================
    Config public config;
    IERC20 public nstToken;

    // 用户积分
    mapping(address => UserPoints) public userPoints;
    address[] public pointsUsers;

    // 空投配置
    struct AirdropConfig {
        uint256 totalPool;          // 本期空投池总量
        uint256 startTime;          // 开始领取时间
        uint256 endTime;            // 结束领取时间
        uint256 totalPointsSnapshot;// 快照时的总积分
        bool isActive;              // 是否激活
        uint256 airdropId;          // 空投期数
    }

    AirdropConfig public currentAirdrop;
    uint256 public airdropCounter;

    // 已领取记录
    mapping(uint256 => mapping(address => bool)) public hasClaimed;  // airdropId => user => claimed
    mapping(uint256 => mapping(address => uint256)) public claimedAmount;  // airdropId => user => amount

    // 积分统计
    uint256 public totalPoints;
    uint256 public totalClaimedPoints;

    // ==================== 事件 ====================
    event PointsAccumulated(
        address indexed user,
        uint256 amount,
        string feeType,
        uint256 timestamp
    );

    event AirdropCreated(
        uint256 indexed airdropId,
        uint256 totalPool,
        uint256 startTime,
        uint256 endTime,
        uint256 timestamp
    );

    event AirdropClaimed(
        address indexed user,
        uint256 indexed airdropId,
        uint256 pointsUsed,
        uint256 tokenAmount,
        uint256 timestamp
    );

    event AirdropEnded(
        uint256 indexed airdropId,
        uint256 totalClaimed,
        uint256 timestamp
    );

    // ==================== 构造函数 ====================
    constructor(
        address _config,
        address _nstToken,
        address _admin
    ) {
        config = Config(_config);
        nstToken = IERC20(_nstToken);
        
        _grantRole(DEFAULT_ADMIN_ROLE, _admin);
        _grantRole(POINTS_OPERATOR_ROLE, _admin);
        _grantRole(AIRDROP_ADMIN_ROLE, _admin);
    }

    // ==================== 修改器 ====================
    modifier onlyOperator() {
        require(hasRole(POINTS_OPERATOR_ROLE, msg.sender), "PointsManager: caller is not operator");
        _;
    }

    modifier onlyAirdropAdmin() {
        require(hasRole(AIRDROP_ADMIN_ROLE, msg.sender), "PointsManager: caller is not airdrop admin");
        _;
    }

    // ==================== 积分功能 ====================

    /**
     * @notice 记录用户手续费积分
     * @param user 用户地址
     * @param feeAmount 手续费金额（以最小单位计）
     * @param feeType 费用类型（"creation", "trading", "arbitration"）
     */
    function recordPoints(
        address user,
        uint256 feeAmount,
        string calldata feeType
    ) external onlyOperator {
        uint256 points = (feeAmount * config.pointsMultiplier()) / 1 ether;
        
        if (userPoints[user].lastUpdateTime == 0) {
            // 新用户
            pointsUsers.push(user);
        }

        userPoints[user].totalPoints += points;
        userPoints[user].availablePoints += points;
        userPoints[user].lastUpdateTime = block.timestamp;

        totalPoints += points;

        emit PointsAccumulated(user, points, feeType, block.timestamp);
    }

    /**
     * @notice 查询用户积分
     */
    function getPoints(address user) external view returns (uint256) {
        return userPoints[user].availablePoints;
    }

    /**
     * @notice 获取用户完整积分信息
     */
    function getUserPoints(address user) external view returns (UserPoints memory) {
        return userPoints[user];
    }

    // ==================== 空投功能 ====================

    /**
     * @notice 创建新一期空投
     * @param totalPool 空投代币总量
     * @param startTime 开始时间
     * @param endTime 结束时间
     */
    function createAirdrop(
        uint256 totalPool,
        uint256 startTime,
        uint256 endTime
    ) external onlyAirdropAdmin {
        require(!currentAirdrop.isActive, "PointsManager: previous airdrop still active");
        require(startTime >= block.timestamp, "PointsManager: start time in past");
        require(endTime > startTime, "PointsManager: invalid time range");
        require(totalPool > 0, "PointsManager: pool must be positive");

        // 确保合约有足够的代币
        require(
            nstToken.balanceOf(address(this)) >= totalPool,
            "PointsManager: insufficient token balance"
        );

        airdropCounter++;

        currentAirdrop = AirdropConfig({
            totalPool: totalPool,
            startTime: startTime,
            endTime: endTime,
            totalPointsSnapshot: totalPoints - totalClaimedPoints,
            isActive: true,
            airdropId: airdropCounter
        });

        emit AirdropCreated(airdropCounter, totalPool, startTime, endTime, block.timestamp);
    }

    /**
     * @notice 领取空投
     */
    function claimAirdrop() external nonReentrant whenNotPaused {
        require(currentAirdrop.isActive, "PointsManager: no active airdrop");
        require(block.timestamp >= currentAirdrop.startTime, "PointsManager: airdrop not started");
        require(block.timestamp <= currentAirdrop.endTime, "PointsManager: airdrop ended");
        require(
            !hasClaimed[currentAirdrop.airdropId][msg.sender],
            "PointsManager: already claimed"
        );

        UserPoints storage user = userPoints[msg.sender];
        require(user.availablePoints > 0, "PointsManager: no points to claim");

        // 计算可领取的代币数量
        // 用户可领取 = 用户可用积分 / 总积分快照 * 总空投池
        uint256 claimable = (user.availablePoints * currentAirdrop.totalPool) / 
                            currentAirdrop.totalPointsSnapshot;

        require(claimable > 0, "PointsManager: nothing to claim");

        // 更新状态
        uint256 pointsUsed = user.availablePoints;
        user.claimedPoints += pointsUsed;
        user.availablePoints = 0;
        totalClaimedPoints += pointsUsed;

        hasClaimed[currentAirdrop.airdropId][msg.sender] = true;
        claimedAmount[currentAirdrop.airdropId][msg.sender] = claimable;

        // 发放代币
        nstToken.safeTransfer(msg.sender, claimable);

        emit AirdropClaimed(
            msg.sender,
            currentAirdrop.airdropId,
            pointsUsed,
            claimable,
            block.timestamp
        );
    }

    /**
     * @notice 查询可领取空投数量
     */
    function getClaimableAirdrop(address user) external view returns (uint256) {
        if (!currentAirdrop.isActive) return 0;
        if (block.timestamp < currentAirdrop.startTime) return 0;
        if (block.timestamp > currentAirdrop.endTime) return 0;
        if (hasClaimed[currentAirdrop.airdropId][user]) return 0;
        if (currentAirdrop.totalPointsSnapshot == 0) return 0;

        uint256 availablePoints = userPoints[user].availablePoints;
        if (availablePoints == 0) return 0;

        return (availablePoints * currentAirdrop.totalPool) / currentAirdrop.totalPointsSnapshot;
    }

    /**
     * @notice 结束当前空投
     */
    function endAirdrop() external onlyAirdropAdmin {
        require(currentAirdrop.isActive, "PointsManager: no active airdrop");
        require(
            block.timestamp > currentAirdrop.endTime,
            "PointsManager: airdrop not ended yet"
        );

        uint256 totalClaimed = 0;
        for (uint256 i = 0; i < pointsUsers.length; i++) {
            totalClaimed += claimedAmount[currentAirdrop.airdropId][pointsUsers[i]];
        }

        currentAirdrop.isActive = false;

        emit AirdropEnded(currentAirdrop.airdropId, totalClaimed, block.timestamp);
    }

    // ==================== 查询功能 ====================

    /**
     * @notice 获取当前空投配置
     */
    function getCurrentAirdrop() external view returns (AirdropConfig memory) {
        return currentAirdrop;
    }

    /**
     * @notice 获取所有积分用户数量
     */
    function getPointsUserCount() external view returns (uint256) {
        return pointsUsers.length;
    }

    /**
     * @notice 获取用户是否已领取指定期数空投
     */
    function hasClaimedAirdrop(uint256 airdropId, address user) external view returns (bool) {
        return hasClaimed[airdropId][user];
    }

    // ==================== 管理功能 ====================

    function setConfig(address _config) external onlyRole(DEFAULT_ADMIN_ROLE) {
        config = Config(_config);
    }

    function setNSTToken(address _nstToken) external onlyRole(DEFAULT_ADMIN_ROLE) {
        nstToken = IERC20(_nstToken);
    }

    function grantOperatorRole(address operator) external onlyRole(DEFAULT_ADMIN_ROLE) {
        grantRole(POINTS_OPERATOR_ROLE, operator);
    }

    /**
     * @notice 紧急提取剩余空投代币（仅空投结束后）
     */
    function withdrawRemainingTokens(address to) external onlyRole(DEFAULT_ADMIN_ROLE) {
        require(!currentAirdrop.isActive, "PointsManager: airdrop still active");
        uint256 balance = nstToken.balanceOf(address(this));
        if (balance > 0) {
            nstToken.safeTransfer(to, balance);
        }
    }

    function pause() external onlyRole(DEFAULT_ADMIN_ROLE) {
        _pause();
    }

    function unpause() external onlyRole(DEFAULT_ADMIN_ROLE) {
        _unpause();
    }
}

contracts/seat/SeatManager.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "@openzeppelin/contracts/token/ERC20/IERC20.sol";
import "@openzeppelin/contracts/token/ERC20/utils/SafeERC20.sol";
import "@openzeppelin/contracts/access/AccessControl.sol";
import "@openzeppelin/contracts/utils/ReentrancyGuard.sol";
import "@openzeppelin/contracts/utils/Pausable.sol";
import "../libraries/NSTTypes.sol";
import "../core/Config.sol";

/**
 * @title SeatManager
 * @notice 席位管理合约 - 席位卖方管理：席位注册、押金、敞口控制
 * @dev 席位押金和最大敞口由后端设定
 */
contract SeatManager is AccessControl, ReentrancyGuard, Pausable {
    using SafeERC20 for IERC20;

    // ==================== 角色定义 ====================
    bytes32 public constant SEAT_OPERATOR_ROLE = keccak256("SEAT_OPERATOR_ROLE");
    bytes32 public constant OPTIONS_CORE_ROLE = keccak256("OPTIONS_CORE_ROLE");

    // ==================== 状态变量 ====================
    Config public config;
    IERC20 public usdt;
    IERC20 public nstToken;

    // 席位存储
    mapping(address => Seat) public seats;
    address[] public seatOwners;

    // ==================== 事件 ====================
    event SeatRegistered(
        address indexed owner,
        uint256 depositAmount,
        uint256 maxExposure,
        uint256 timestamp
    );

    event SeatDeactivated(
        address indexed owner,
        string reason,
        uint256 timestamp
    );

    event SeatReactivated(
        address indexed owner,
        uint256 timestamp
    );

    event DepositUpdated(
        address indexed owner,
        uint256 oldAmount,
        uint256 newAmount,
        uint256 timestamp
    );

    event ExposureUpdated(
        address indexed owner,
        uint256 oldExposure,
        uint256 newExposure,
        bool isIncrease,
        uint256 timestamp
    );

    event NSTStaked(
        address indexed owner,
        uint256 amount,
        uint256 timestamp
    );

    event NSTUnstaked(
        address indexed owner,
        uint256 amount,
        uint256 timestamp
    );

    event SeatParamsUpdated(
        address indexed owner,
        uint256 depositAmount,
        uint256 maxExposure,
        uint256 timestamp
    );

    // ==================== 构造函数 ====================
    constructor(
        address _config,
        address _usdt,
        address _nstToken,
        address _admin
    ) {
        config = Config(_config);
        usdt = IERC20(_usdt);
        nstToken = IERC20(_nstToken);
        
        _grantRole(DEFAULT_ADMIN_ROLE, _admin);
        _grantRole(SEAT_OPERATOR_ROLE, _admin);
    }

    // ==================== 修改器 ====================
    modifier onlyOperator() {
        require(hasRole(SEAT_OPERATOR_ROLE, msg.sender), "SeatManager: caller is not operator");
        _;
    }

    modifier onlyOptionsCore() {
        require(hasRole(OPTIONS_CORE_ROLE, msg.sender), "SeatManager: caller is not OptionsCore");
        _;
    }

    modifier validSeatOwner(address owner) {
        require(seats[owner].owner != address(0), "SeatManager: seat not registered");
        _;
    }

    // ==================== 席位注册 ====================

    /**
     * @notice 注册席位（需要后端设定押金和敞口）
     * @param depositAmount 席位押金（后端设定）
     */
    function registerSeat(uint256 depositAmount) external nonReentrant whenNotPaused {
        require(seats[msg.sender].owner == address(0), "SeatManager: seat already registered");
        require(depositAmount > 0, "SeatManager: deposit must be positive");

        // 收取押金
        usdt.safeTransferFrom(msg.sender, address(this), depositAmount);

        // 创建席位
        seats[msg.sender] = Seat({
            owner: msg.sender,
            depositAmount: depositAmount,
            nstStaked: 0,
            stakeStartTime: 0,
            currentExposure: 0,
            maxExposure: 0,  // 由后端设定
            isActive: true
        });

        seatOwners.push(msg.sender);

        emit SeatRegistered(msg.sender, depositAmount, 0, block.timestamp);
    }

    /**
     * @notice 后端设置席位参数
     * @param seller 卖方地址
     * @param depositAmount 押金金额
     * @param maxExposure 最大敞口
     */
    function setSeatParams(
        address seller,
        uint256 depositAmount,
        uint256 maxExposure
    ) external onlyOperator validSeatOwner(seller) {
        Seat storage seat = seats[seller];
        
        seat.depositAmount = depositAmount;
        seat.maxExposure = maxExposure;

        emit SeatParamsUpdated(seller, depositAmount, maxExposure, block.timestamp);
    }

    // ==================== 押金管理 ====================

    /**
     * @notice 追加押金
     * @param amount 追加金额
     */
    function addDeposit(uint256 amount) external nonReentrant whenNotPaused validSeatOwner(msg.sender) {
        require(amount > 0, "SeatManager: amount must be positive");

        Seat storage seat = seats[msg.sender];
        uint256 oldAmount = seat.depositAmount;

        usdt.safeTransferFrom(msg.sender, address(this), amount);
        seat.depositAmount += amount;

        emit DepositUpdated(msg.sender, oldAmount, seat.depositAmount, block.timestamp);
    }

    /**
     * @notice 提取押金（需确保无敞口）
     * @param amount 提取金额
     */
    function withdrawDeposit(uint256 amount) external nonReentrant whenNotPaused validSeatOwner(msg.sender) {
        Seat storage seat = seats[msg.sender];
        require(seat.currentExposure == 0, "SeatManager: has active exposure");
        require(seat.depositAmount >= amount, "SeatManager: insufficient deposit");

        uint256 oldAmount = seat.depositAmount;
        seat.depositAmount -= amount;
        usdt.safeTransfer(msg.sender, amount);

        emit DepositUpdated(msg.sender, oldAmount, seat.depositAmount, block.timestamp);
    }

    // ==================== 敞口管理 ====================

    /**
     * @notice 更新风险敞口（由 OptionsCore 调用）
     * @param seller 卖方地址
     * @param notional 名义本金
     * @param isAdd 是否增加敞口
     */
    function updateExposure(
        address seller,
        uint256 notional,
        bool isAdd
    ) external onlyOptionsCore validSeatOwner(seller) {
        Seat storage seat = seats[seller];
        uint256 oldExposure = seat.currentExposure;

        if (isAdd) {
            require(
                seat.currentExposure + notional <= seat.maxExposure,
                "SeatManager: exceeds max exposure"
            );
            seat.currentExposure += notional;
        } else {
            require(seat.currentExposure >= notional, "SeatManager: insufficient exposure");
            seat.currentExposure -= notional;
        }

        emit ExposureUpdated(seller, oldExposure, seat.currentExposure, isAdd, block.timestamp);
    }

    // ==================== NST 质押 ====================

    /**
     * @notice 质押 NST（后期功能）
     * @param amount 质押金额
     */
    function stakeNST(uint256 amount) external nonReentrant whenNotPaused validSeatOwner(msg.sender) {
        require(amount > 0, "SeatManager: amount must be positive");
        require(address(nstToken) != address(0), "SeatManager: NST token not set");

        Seat storage seat = seats[msg.sender];

        nstToken.safeTransferFrom(msg.sender, address(this), amount);
        
        if (seat.nstStaked == 0) {
            seat.stakeStartTime = block.timestamp;
        }
        seat.nstStaked += amount;

        emit NSTStaked(msg.sender, amount, block.timestamp);
    }

    /**
     * @notice 解除 NST 质押
     * @param amount 解除金额
     */
    function unstakeNST(uint256 amount) external nonReentrant whenNotPaused validSeatOwner(msg.sender) {
        Seat storage seat = seats[msg.sender];
        require(seat.nstStaked >= amount, "SeatManager: insufficient staked amount");
        require(seat.currentExposure == 0, "SeatManager: has active exposure");

        seat.nstStaked -= amount;
        if (seat.nstStaked == 0) {
            seat.stakeStartTime = 0;
        }
        nstToken.safeTransfer(msg.sender, amount);

        emit NSTUnstaked(msg.sender, amount, block.timestamp);
    }

    // ==================== 席位状态管理 ====================

    /**
     * @notice 停用席位
     * @param owner 席位持有人
     * @param reason 停用原因
     */
    function deactivateSeat(address owner, string calldata reason) external onlyOperator validSeatOwner(owner) {
        seats[owner].isActive = false;
        emit SeatDeactivated(owner, reason, block.timestamp);
    }

    /**
     * @notice 重新激活席位
     * @param owner 席位持有人
     */
    function reactivateSeat(address owner) external onlyOperator validSeatOwner(owner) {
        seats[owner].isActive = true;
        emit SeatReactivated(owner, block.timestamp);
    }

    // ==================== 查询功能 ====================

    /**
     * @notice 检查席位是否有效
     */
    function isValidSeat(address seller) external view returns (bool) {
        Seat storage seat = seats[seller];
        return seat.owner != address(0) && seat.isActive;
    }

    /**
     * @notice 获取席位信息
     */
    function getSeat(address owner) external view returns (Seat memory) {
        return seats[owner];
    }

    /**
     * @notice 获取所有席位持有人
     */
    function getAllSeatOwners() external view returns (address[] memory) {
        return seatOwners;
    }

    /**
     * @notice 获取席位持有人数量
     */
    function getSeatCount() external view returns (uint256) {
        return seatOwners.length;
    }

    /**
     * @notice 检查是否可以承接指定金额的订单
     */
    function canTakeOrder(address seller, uint256 notional) external view returns (bool) {
        Seat storage seat = seats[seller];
        return seat.isActive && 
               seat.currentExposure + notional <= seat.maxExposure;
    }

    // ==================== 管理功能 ====================

    function setConfig(address _config) external onlyRole(DEFAULT_ADMIN_ROLE) {
        config = Config(_config);
    }

    function setNSTToken(address _nstToken) external onlyRole(DEFAULT_ADMIN_ROLE) {
        nstToken = IERC20(_nstToken);
    }

    function grantOptionsCoreRole(address _optionsCore) external onlyRole(DEFAULT_ADMIN_ROLE) {
        grantRole(OPTIONS_CORE_ROLE, _optionsCore);
    }

    function pause() external onlyRole(DEFAULT_ADMIN_ROLE) {
        _pause();
    }

    function unpause() external onlyRole(DEFAULT_ADMIN_ROLE) {
        _unpause();
    }
}

contracts/vault/VaultManager.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "@openzeppelin/contracts/token/ERC20/IERC20.sol";
import "@openzeppelin/contracts/token/ERC20/utils/SafeERC20.sol";
import "@openzeppelin/contracts/access/AccessControl.sol";
import "@openzeppelin/contracts/utils/ReentrancyGuard.sol";
import "@openzeppelin/contracts/utils/Pausable.sol";
import "../core/Config.sol";

/**
 * @title VaultManager
 * @notice 资金池管理合约 - 资金调度与状态执行中枢
 * @dev 只接受授权的合约调用，不直接与用户交互
 */
contract VaultManager is AccessControl, ReentrancyGuard, Pausable {
    using SafeERC20 for IERC20;

    // ==================== 角色定义 ====================
    bytes32 public constant VAULT_OPERATOR_ROLE = keccak256("VAULT_OPERATOR_ROLE");

    // ==================== 状态变量 ====================
    Config public config;
    
    // 资金池余额
    mapping(address => uint256) public marginPoolBalance;       // 保证金池
    mapping(address => uint256) public profitPoolBalance;       // 生态利润池
    mapping(address => uint256) public lpPoolBalance;           // 代币LP池
    mapping(address => uint256) public interactPoolBalance;     // 合约交互池
    mapping(address => uint256) public donationPoolBalance;     // 捐赠节点池

    // 用户保证金余额
    mapping(address => mapping(address => uint256)) public userMarginBalance;  // user => token => balance

    // ==================== 事件 ====================
    event MarginDeposited(
        address indexed user,
        address indexed token,
        uint256 amount,
        uint256 timestamp
    );

    event MarginWithdrawn(
        address indexed user,
        address indexed token,
        uint256 amount,
        uint256 timestamp
    );

    event MarginTransferred(
        address indexed from,
        address indexed to,
        address indexed token,
        uint256 amount,
        string reason,
        uint256 timestamp
    );

    event FeeCollected(
        address indexed token,
        uint256 amount,
        string feeType,
        uint256 timestamp
    );

    event ProfitDistributed(
        address indexed token,
        uint256 amount,
        string poolType,
        uint256 timestamp
    );

    // ==================== 构造函数 ====================
    constructor(address _config, address _admin) {
        config = Config(_config);
        _grantRole(DEFAULT_ADMIN_ROLE, _admin);
        _grantRole(VAULT_OPERATOR_ROLE, _admin);
    }

    // ==================== 修改器 ====================
    modifier onlyOperator() {
        require(hasRole(VAULT_OPERATOR_ROLE, msg.sender), "VaultManager: caller is not operator");
        _;
    }

    // ==================== 保证金操作 ====================

    /**
     * @notice 存入保证金
     * @param _user 用户地址
     * @param _token 代币地址
     * @param _amount 金额
     */
    function depositMargin(
        address _user,
        address _token,
        uint256 _amount
    ) external onlyOperator nonReentrant whenNotPaused {
        require(_amount > 0, "VaultManager: amount must be greater than 0");
        
        IERC20(_token).safeTransferFrom(_user, address(this), _amount);
        userMarginBalance[_user][_token] += _amount;
        marginPoolBalance[_token] += _amount;

        emit MarginDeposited(_user, _token, _amount, block.timestamp);
    }

    /**
     * @notice 提取保证金
     * @param _user 用户地址
     * @param _token 代币地址
     * @param _amount 金额
     */
    function withdrawMargin(
        address _user,
        address _token,
        uint256 _amount
    ) external onlyOperator nonReentrant whenNotPaused {
        require(_amount > 0, "VaultManager: amount must be greater than 0");
        require(userMarginBalance[_user][_token] >= _amount, "VaultManager: insufficient balance");

        userMarginBalance[_user][_token] -= _amount;
        marginPoolBalance[_token] -= _amount;
        IERC20(_token).safeTransfer(_user, _amount);

        emit MarginWithdrawn(_user, _token, _amount, block.timestamp);
    }

    /**
     * @notice 内部转移保证金（订单结算时使用）
     * @param _from 发送方
     * @param _to 接收方
     * @param _token 代币地址
     * @param _amount 金额
     * @param _reason 转移原因
     */
    function transferMargin(
        address _from,
        address _to,
        address _token,
        uint256 _amount,
        string calldata _reason
    ) external onlyOperator nonReentrant whenNotPaused {
        require(userMarginBalance[_from][_token] >= _amount, "VaultManager: insufficient balance");

        userMarginBalance[_from][_token] -= _amount;
        userMarginBalance[_to][_token] += _amount;

        emit MarginTransferred(_from, _to, _token, _amount, _reason, block.timestamp);
    }

    // ==================== 手续费操作 ====================

    /**
     * @notice 收取手续费
     * @param _user 用户地址
     * @param _token 代币地址
     * @param _amount 金额
     * @param _feeType 费用类型
     */
    function collectFee(
        address _user,
        address _token,
        uint256 _amount,
        string calldata _feeType
    ) external onlyOperator nonReentrant whenNotPaused {
        require(_amount > 0, "VaultManager: amount must be greater than 0");

        IERC20(_token).safeTransferFrom(_user, address(this), _amount);
        profitPoolBalance[_token] += _amount;

        emit FeeCollected(_token, _amount, _feeType, block.timestamp);
    }

    /**
     * @notice 分配利润到各池子
     * @param _token 代币地址
     * @param _amount 总金额
     */
    function distributeProfits(
        address _token,
        uint256 _amount
    ) external onlyOperator nonReentrant whenNotPaused {
        require(profitPoolBalance[_token] >= _amount, "VaultManager: insufficient profit pool");

        profitPoolBalance[_token] -= _amount;

        // 按比例分配
        uint256 nodeReward = (_amount * config.nodeRewardShare()) / 10000;
        uint256 buyback = (_amount * config.tokenBuybackShare()) / 10000;
        uint256 lp = (_amount * config.lpPoolShare()) / 10000;
        // 剩余部分分配给团队、基金会、DAO、成长节点
        // 这里简化处理，实际需要转账到对应地址

        lpPoolBalance[_token] += lp;
        donationPoolBalance[_token] += nodeReward;

        emit ProfitDistributed(_token, _amount, "all", block.timestamp);
    }

    // ==================== 喂价费用操作 ====================

    /**
     * @notice 转移喂价费用到喂价生态
     * @param _token 代币地址
     * @param _amount 金额
     * @param _feedProtocol 喂价协议地址
     */
    function transferToFeedProtocol(
        address _token,
        uint256 _amount,
        address _feedProtocol
    ) external onlyOperator nonReentrant whenNotPaused {
        interactPoolBalance[_token] -= _amount;
        IERC20(_token).safeTransfer(_feedProtocol, _amount);
    }

    // ==================== 查询函数 ====================

    /**
     * @notice 查询用户保证金余额
     */
    function getUserMarginBalance(
        address _user,
        address _token
    ) external view returns (uint256) {
        return userMarginBalance[_user][_token];
    }

    /**
     * @notice 查询总保证金池余额
     */
    function getTotalMarginPool(address _token) external view returns (uint256) {
        return marginPoolBalance[_token];
    }

    /**
     * @notice 查询利润池余额
     */
    function getProfitPoolBalance(address _token) external view returns (uint256) {
        return profitPoolBalance[_token];
    }

    // ==================== 管理函数 ====================

    /**
     * @notice 更新 Config 地址
     */
    function setConfig(address _config) external onlyRole(DEFAULT_ADMIN_ROLE) {
        config = Config(_config);
    }

    /**
     * @notice 授权操作者角色
     */
    function grantOperatorRole(address _operator) external onlyRole(DEFAULT_ADMIN_ROLE) {
        grantRole(VAULT_OPERATOR_ROLE, _operator);
    }

    /**
     * @notice 暂停合约
     */
    function pause() external onlyRole(DEFAULT_ADMIN_ROLE) {
        _pause();
    }

    /**
     * @notice 恢复合约
     */
    function unpause() external onlyRole(DEFAULT_ADMIN_ROLE) {
        _unpause();
    }
}

